// Validate Twilio signature via HMAC-SHA1
const headers = $('Webhook').item.json.headers;
const body = $('Webhook').item.json.body;
const twilioSig = headers['x-twilio-signature'];

if (!twilioSig) throw new Error('Missing Twilio signature');

const url = `https://your-instance.app.n8n.cloud/webhook/respondfall/twilio-inbound`;

// Build sorted param string for HMAC
const sorted = Object.keys(body).sort().map(k => `${k}${body[k]}`).join('');
const toSign = url + sorted;

const key = await crypto.subtle.importKey(
  'raw',
  new TextEncoder().encode($vars.RESPONDFALL_TWILIO_AUTH_TOKEN),
  { name: 'HMAC', hash: 'SHA-1' },
  false,
  ['sign']
);
const sig = await crypto.subtle.sign('HMAC', key, new TextEncoder().encode(toSign));
const expected = btoa(String.fromCharCode(...new Uint8Array(sig)));

if (expected !== twilioSig) throw new Error('Invalid Twilio signature');

// Identify call type
const callStatus = body.CallStatus;
const msgBody = body.Body;
const isVoice = !!body.CallSid && !body.Body;
const isVoiceStatus = !!callStatus && !body.Body;
const isSms = !!body.MessageSid;

return [{ json: { body, isVoice, isVoiceStatus, isSms, callStatus, msgBody } }];

// Return TwiML to forward the call to the real business phone
const body = $('Validate Twilio Signature').item.json.body;
const calledNumber = body.To;

// Look up client by respondfall_number
const res = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/clients?respondfall_number=eq.${encodeURIComponent(calledNumber)}&select=id,business_phone,business_name,system_active`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const clients = await res.json();
if (!clients.length) throw new Error('Client not found for number: ' + calledNumber);
const client = clients[0];

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Dial action="https://your-instance.app.n8n.cloud/webhook/respondfall/twilio-inbound" method="POST" timeout="20">
    <Number statusCallbackEvent="completed" statusCallback="https://your-instance.app.n8n.cloud/webhook/respondfall/twilio-inbound" statusCallbackMethod="POST">${client.business_phone}</Number>
  </Dial>
</Response>`;

return [{ json: { twiml, clientId: client.id, businessPhone: client.business_phone, systemActive: client.system_active } }];

// Handle call StatusCallback — detect missed call
const body = $('Validate Twilio Signature').item.json.body;
const callStatus = body.CallStatus;
const isSms = $('Validate Twilio Signature').item.json.isSms;

// If this is the voice status callback
if (!isSms && callStatus) {
  const calledNumber = body.To;
  const callerNumber = body.From || body.Called;
  const callSid = body.CallSid;
  const isMissed = ['no-answer', 'busy', 'failed'].includes(callStatus);

  if (!isMissed) {
    return [{ json: { skip: true, reason: `Call status: ${callStatus}` } }];
  }

  // Look up client
  const clientRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/clients?respondfall_number=eq.${encodeURIComponent(calledNumber)}&select=id,business_name,system_active,step1_template,step2_template,step2_delay_hours,respondfall_number`,
    { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
  );
  const clients = await clientRes.json();
  if (!clients.length) return [{ json: { skip: true, reason: 'No client found' } }];
  const client = clients[0];

  if (!client.system_active) return [{ json: { skip: true, reason: 'System inactive' } }];

  // Dedup: check missed_calls for this call_sid
  const dupRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/missed_calls?call_sid=eq.${callSid}&select=id`,
    { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
  );
  const dups = await dupRes.json();
  if (dups.length) return [{ json: { skip: true, reason: 'Duplicate call_sid' } }];

  // Check opt-out
  const optRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/opt_outs?client_id=eq.${client.id}&phone=eq.${encodeURIComponent(callerNumber)}&select=id`,
    { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
  );
  const opts = await optRes.json();
  if (opts.length) return [{ json: { skip: true, reason: 'Opted out' } }];

  // Blackout check (9pm–8am local, approximate UTC)
  const hour = new Date().getUTCHours();
  if (hour >= 1 && hour < 12) return [{ json: { skip: true, reason: 'Blackout window' } }];

  // Record missed call
  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/missed_calls`, {
    method: 'POST',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ client_id: client.id, caller_phone: callerNumber, call_sid: callSid, call_status: callStatus }),
  });

  // Find or create conversation
  let convRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?client_id=eq.${client.id}&lead_phone=eq.${encodeURIComponent(callerNumber)}&status=eq.open&select=id`,
    { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
  );
  let convs = await convRes.json();
  let conversationId;
  if (convs.length) {
    conversationId = convs[0].id;
  } else {
    const newConv = await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations`, {
      method: 'POST',
      headers: {
        apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
        Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
        'Content-Type': 'application/json',
        Prefer: 'return=representation',
      },
      body: JSON.stringify({ client_id: client.id, lead_phone: callerNumber, status: 'open', opted_out: false }),
    });
    const newConvData = await newConv.json();
    conversationId = newConvData[0].id;
  }

  // Build Step 1 message
  const step1Body = (client.step1_template ?? "Hi! We just missed your call. We'd love to help — what do you need?")
    .replace('{{business_name}}', client.business_name);

  // Send Step 1 immediately via Twilio
  const smsRes = await fetch(`https://api.twilio.com/2010-04-01/Accounts/${$vars.RESPONDFALL_TWILIO_ACCOUNT_SID}/Messages.json`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${btoa($vars.RESPONDFALL_TWILIO_ACCOUNT_SID + ':' + $vars.RESPONDFALL_TWILIO_AUTH_TOKEN)}`,
    },
    body: new URLSearchParams({ To: callerNumber, From: client.respondfall_number, Body: step1Body }).toString(),
  });
  const smsData = await smsRes.json();

  // Insert Step 1 message
  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
    method: 'POST',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ conversation_id: conversationId, direction: 'outbound', body: step1Body, message_type: 'step1', twilio_sid: smsData.sid }),
  });

  // Schedule Step 2
  const delayHours = client.step2_delay_hours ?? 24;
  const scheduledAt = new Date(Date.now() + delayHours * 60 * 60 * 1000).toISOString();
  const step2Body = (client.step2_template ?? "Hey, just checking in! Did you get a chance to connect with us?")
    .replace('{{business_name}}', client.business_name);

  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
    method: 'POST',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ conversation_id: conversationId, direction: 'outbound', body: step2Body, message_type: 'step2', scheduled_at: scheduledAt }),
  });

  return [{ json: { handled: 'missed_call', conversationId } }];
}

// If we get here it's an SMS — pass through
return [{ json: $('Validate Twilio Signature').item.json }];

// Handle inbound SMS: STOP, referral reply, AI qualification
const validated = $('Validate Twilio Signature').item.json;
const body = validated.body;
const fromPhone = body.From;
const toPhone = body.To;
const msgText = (body.Body ?? '').trim();
const msgUpper = msgText.toUpperCase();

// Look up client
const clientRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/clients?respondfall_number=eq.${encodeURIComponent(toPhone)}&select=id,business_name,system_active,respondfall_number,business_phone,agency_owner_id`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const clients = await clientRes.json();
if (!clients.length) return [{ json: { skip: true, reason: 'No client' } }];
const client = clients[0];

// Handle STOP
if (['STOP', 'UNSUBSCRIBE', 'CANCEL', 'QUIT', 'END'].includes(msgUpper)) {
  // Mark conversation opted_out
  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?client_id=eq.${client.id}&lead_phone=eq.${encodeURIComponent(fromPhone)}`, {
    method: 'PATCH',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ opted_out: true, status: 'opted_out' }),
  });
  // Insert opt_out record
  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/opt_outs`, {
    method: 'POST',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ client_id: client.id, phone: fromPhone }),
  });
  return [{ json: { handled: 'stop', twiml: '<?xml version="1.0" encoding="UTF-8"?><Response></Response>' } }];
}

// Find open conversation
const convRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?client_id=eq.${client.id}&lead_phone=eq.${encodeURIComponent(fromPhone)}&status=eq.open&select=id,status&order=created_at.desc&limit=1`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const convs = await convRes.json();
if (!convs.length) return [{ json: { skip: true, reason: 'No open conversation' } }];
const conv = convs[0];

// Insert inbound message
await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
  method: 'POST',
  headers: {
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ conversation_id: conv.id, direction: 'inbound', body: msgText, message_type: 'inbound', twilio_sid: body.MessageSid }),
});

// Check last outbound for referral context
const lastMsgRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages?conversation_id=eq.${conv.id}&direction=eq.outbound&order=created_at.desc&limit=1&select=message_type`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const lastMsgs = await lastMsgRes.json();
const lastType = lastMsgs[0]?.message_type;

if (lastType === 'referral') {
  // This reply is a referral name
  const code = 'REF-' + Math.random().toString(36).toUpperCase().slice(2, 8);
  await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/referrals`, {
    method: 'POST',
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ client_id: client.id, conversation_id: conv.id, referral_name: msgText, referral_code: code }),
  });
  // Send confirmation
  await fetch(`https://api.twilio.com/2010-04-01/Accounts/${$vars.RESPONDFALL_TWILIO_ACCOUNT_SID}/Messages.json`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${btoa($vars.RESPONDFALL_TWILIO_ACCOUNT_SID + ':' + $vars.RESPONDFALL_TWILIO_AUTH_TOKEN)}`,
    },
    body: new URLSearchParams({ To: fromPhone, From: client.respondfall_number, Body: `Thanks for the referral! Your friend's code is ${code}. We'll reach out to them soon!` }).toString(),
  });
  return [{ json: { handled: 'referral', code } }];
}

// AI qualification via Claude
const aiRes = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key': $vars.RESPONDFALL_ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    model: 'claude-sonnet-4-6',
    max_tokens: 300,
    system: `You are a friendly SMS assistant for ${client.business_name}. Your job is to qualify missed-call leads via text. Keep replies to 1-2 sentences max. Be warm and professional. If the lead clearly wants a quote/appointment, say so in your reply and end with a question to get their details. If they have a question you can't answer, say a team member will follow up shortly. Always reply in plain SMS-friendly text, no markdown.`,
    messages: [{ role: 'user', content: msgText }],
  }),
});
const aiData = await aiRes.json();
const aiReply = aiData.content?.[0]?.text ?? "Thanks for reaching out! A team member will follow up with you shortly.";

// Classify intent
const intentKeywords = ['quote', 'price', 'appointment', 'schedule', 'book', 'cost', 'estimate', 'available'];
const isHighIntent = intentKeywords.some(kw => msgUpper.includes(kw.toUpperCase()));
const isQuestion = msgText.includes('?');

// Send AI reply
const replySms = await fetch(`https://api.twilio.com/2010-04-01/Accounts/${$vars.RESPONDFALL_TWILIO_ACCOUNT_SID}/Messages.json`, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    Authorization: `Basic ${btoa($vars.RESPONDFALL_TWILIO_ACCOUNT_SID + ':' + $vars.RESPONDFALL_TWILIO_AUTH_TOKEN)}`,
  },
  body: new URLSearchParams({ To: fromPhone, From: client.respondfall_number, Body: aiReply }).toString(),
});
const replyData = await replySms.json();

// Insert AI reply message
await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
  method: 'POST',
  headers: {
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ conversation_id: conv.id, direction: 'outbound', body: aiReply, message_type: 'ai_reply', twilio_sid: replyData.sid }),
});

// If it's a question, alert owner via SMS
if (isQuestion) {
  const ownerRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/agency_owners?id=eq.${client.agency_owner_id}&select=notification_phone`,
    { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
  );
  const owners = await ownerRes.json();
  const ownerPhone = owners[0]?.notification_phone;
  if (ownerPhone) {
    await fetch(`https://api.twilio.com/2010-04-01/Accounts/${$vars.RESPONDFALL_TWILIO_ACCOUNT_SID}/Messages.json`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Authorization: `Basic ${btoa($vars.RESPONDFALL_TWILIO_ACCOUNT_SID + ':' + $vars.RESPONDFALL_TWILIO_AUTH_TOKEN)}`,
      },
      body: new URLSearchParams({ To: ownerPhone, From: client.respondfall_number, Body: `[Respondfall] Lead question from ${fromPhone}: "${msgText}" — log in to reply.` }).toString(),
    });
  }
}

return [{ json: { handled: 'sms', isHighIntent, aiReply } }];
